# Count collections and APIs recursively
function Count-Items($items) {
    $count = 0
    foreach ($item in $items) {
        if ($item.api) { $count++ }
        if ($item.items) { $count += Count-Items($item.items) }
    }
    return $count
}

$totalApis = Count-Items($json.apiCollection)
Write-Output "Total API endpoints: $totalApis"

# List all folder names and API paths
function List-Items($items, $depth) {
    foreach ($item in $items) {
        $indent = "  " * $depth
        if ($item.api) {
            Write-Output "$indent[API] $($item.api.method.ToUpper()) $($item.api.path)"
        } else {
            Write-Output "$indent[FOLDER] $($item.name)"
            if ($item.items) { List-Items $item.items ($depth + 1) }
        }
    }
}

